/** Look up token metadata by code and issuer. */
export function lookupToken(code: string, issuer?: string | null): TokenMeta | null {
  // Try CODE:ISSUER exact match first
  if (issuer) {
    const key = `${code.toUpperCase()}:${issuer}`;
    if (TOKEN_REGISTRY[key]) return TOKEN_REGISTRY[key]!;
  }
  // Fallback: first match by code only (for tokens with single issuer like USDC)
  const codeUpper = code.toUpperCase();
  for (const [k, v] of Object.entries(TOKEN_REGISTRY)) {
    if (k.startsWith(codeUpper + ":")) return v;
  }
  return null;
}